#include<bits/stdc++.h>
using namespace std;
const long long MAXN=300000+10;
long long n,m,k,cmd,x,t,a[MAXN]; 
deque<long long> dq;
int main(void){
	cin>>n>>m>>k;
	for(long long i=1;i<=n;i++)cin>>a[i];
	sort(a+1,a+1+n);
	for(long long i=1;i<=n;i++)dq.push_back(a[i]); 
	for(long long i=1;i<=m;i++){
		cin>>cmd;
		if(cmd==3)cout<<dq.size()<<'\n';
		else if(cmd==1){
			cin>>x;
			t+=x;
			while(!dq.empty()){
				long long v=dq.back();
				if(v+t>k)dq.pop_back();
				else break;
			}
		}else if(cmd==2){
			cin>>x;
			t-=x;
			while(!dq.empty()){
				long long v=dq.front();
				if(v+t<(-k))dq.pop_front();
				else break;
			}
		}
	}
	return false;
}
